pub fn adler32_combine(adler1: u32, adler2: u32, len2: u64) -> u32 {
    const BASE: u32 = 65521;
    let rem = (len2 % (BASE as u64)) as u32;
    let mut sum1: u32 = adler1 & 0xffff;
    let mut sum2: u32 = (rem.wrapping_mul(sum1)) % BASE;
    sum1 = sum1.wrapping_add((adler2 & 0xffff).wrapping_add(BASE).wrapping_sub(1));
    sum2 = sum2.wrapping_add(((adler1 >> 16) & 0xffff).wrapping_add((adler2 >> 16) & 0xffff).wrapping_add(BASE).wrapping_sub(rem));
    if sum1 >= BASE { sum1 -= BASE; }
    if sum1 >= BASE { sum1 -= BASE; }
    if sum2 >= BASE.wrapping_mul(2) { sum2 -= BASE.wrapping_mul(2); }
    if sum2 >= BASE { sum2 -= BASE; }
    sum1 | (sum2 << 16)
}
